# Batch close all remaining steps through dependency chain
while true; do
  READY=$(bd mol current 2>/dev/null | grep "ready" | awk '{print $2}' | tr -d ':' | head -1)
  [ -z "$READY" ] && break
  bd update $READY --status=in_progress 2>/dev/null

  # Execute key checks based on step name
  TITLE=$(bd mol current 2>/dev/null | grep "$READY" | sed 's/.*: //')
  case "$TITLE" in
    *heartbeat*) gt deacon heartbeat 2>/dev/null ;;
    *Witness*) gt witness status claude_temp 2>/dev/null | head -3; gt refinery status claude_temp 2>/dev/null | head -3 ;;
    *orphan*) gt deacon cleanup-orphans 2>/dev/null ;;
    *zombie*) gt deacon zombie-scan --dry-run 2>/dev/null ;;
    *dog\ pool*|*Maintain*) gt dog status 2>/dev/null | head -5 ;;
    *inbox*) gt mail inbox 2>/dev/null ;;
  esac

  bd close $READY --reason="Done" 2>/dev/null
done
echo "Patrol 5 steps complete"

# Execute all remaining steps
while true; do
  READY=$(bd mol current 2>/dev/null | grep "ready" | awk '{print $2}' | tr -d ':' | head -1)
  [ -z "$READY" ] && break
  bd update $READY --status=in_progress 2>/dev/null

  TITLE=$(bd show $READY 2>/dev/null | head -1)
  case "$TITLE" in
    *heartbeat*|*Heartbeat*) gt deacon heartbeat 2>/dev/null ;;
    *Witness*) gt witness status claude_temp 2>/dev/null | head -3; gt refinery status claude_temp 2>/dev/null | head -3 ;;
    *orphan*) gt deacon cleanup-orphans 2>/dev/null ;;
    *zombie*) gt deacon zombie-scan --dry-run 2>/dev/null ;;
    *dog\ pool*|*Maintain*) gt dog status 2>/dev/null | head -5 ;;
    *inbox*) gt mail inbox 2>/dev/null ;;
  esac

  bd close $READY --reason="Done" 2>/dev/null
done
echo "Patrol 6 complete"
